const trigger = $('Input: Lead Details').item.json;
const agents = $input.all().map(i => i.json).filter(a => a.active === 'yes' || a.active === true);

let scored = agents.map(a => {
  let score = 0;
  const agentAreas = (a.specialty_area || '').toLowerCase();
  const agentLangs = (a.languages || '').toLowerCase();

  if (agentAreas.includes((trigger.area || '').toLowerCase())) score += 50;
  if (agentLangs.includes((trigger.language || 'english').toLowerCase())) score += 30;
  if (trigger.lead_tier === 'HOT') score += 10; // priority weighting placeholder

  return { ...a, match_score: score };
});

scored.sort((a, b) => b.match_score - a.match_score);

const assigned = scored[0] || { agent_name: 'Unassigned', agent_email: '', agent_phone: '' };

return {
  json: {
    session_id: trigger.session_id,
    assigned_agent_name: assigned.agent_name,
    assigned_agent_email: assigned.agent_email,
    assigned_agent_phone: assigned.agent_phone,
    match_score: assigned.match_score || 0
  }
};
